mapper.select:
SELECT sc.id, sc.dept_id AS deptId, d.dept_name AS deptName, sc.staff_id AS staffId, st.name AS staffName, sc.work_date AS workDate, sc.time_period AS timePeriod, sc.total_count AS totalCount, sc.remaining_count AS remainingCount, sc.register_fee AS registerFee FROM schedule sc LEFT JOIN dept d ON d.id = sc.dept_id LEFT JOIN staff st ON st.id = sc.staff_id
AND sc.dept_id = #{deptId} AND sc.work_date = #{workDate} AND sc.staff_id = #{staffId}
ORDER BY sc.work_date, sc.id

mapper.update:
UPDATE schedule
total_count = #{totalCount}, remaining_count = #{remainingCount}, register_fee = #{registerFee},
WHERE id = #{id}
